.darma-loader-darma-custom-197 {
  color: #ea580c;
height: 15px;
aspect-ratio: 4;
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
background:
var(--_g) left,
var(--_g) right;
background-size: 25% 100%;
display: grid;
}
.darma-loader-darma-custom-197:before,
.darma-loader-darma-custom-197:after {
content: "";
grid-area: 1/1;
margin: auto;
height: 100%;
aspect-ratio: 1;
border-radius: 50%;
background: currentColor;
clip-path: inset(0 0 49%);
transform-origin: -100% 50%;
animation: darma-loader-darma-custom-197-l27 .5s infinite alternate;
}
.darma-loader-darma-custom-197:after {
--s:-1;
transform-origin: 200% 50%;
}
@keyframes darma-loader-darma-custom-197-l27 {
0%,40% {transform:scaleY(var(--s,1)) rotate(0)}
100% {transform:scaleY(var(--s,1)) rotate(calc(var(--s,1)*-90deg))}
}

